// C# 12: Primary Constructor
public class OrderService(
    IOrderRepository repo,
    IProductService productSvc,
    ILogger<OrderService> logger,
    TimeProvider time)
{
    public async Task<Order> CreateAsync(CreateOrderDto dto, CancellationToken ct)
    {
        // repo, productSvc, logger, time đều available trực tiếp
        var product = await productSvc.GetAsync(dto.ProductId, ct);
        if (product is null)
            throw new NotFoundException($"Product {dto.ProductId} not found");

        logger.LogInformation("Creating order for product {ProductId}", dto.ProductId);

        return await repo.CreateAsync(new Order
        {
            ProductId = dto.ProductId,
            Quantity = dto.Quantity,
            CreatedAt = time.GetUtcNow()
        }, ct);
    }
}

